Hi @heatherlb!

Modify the code to get the current filters, then update it with the selected value:

```js
var $table = $('#mytable');
$('.multilocation')
  .on('change', function(){
    var myLocations = "";
    var filters = $.tablesorter.getFilters($table);
    filters[2] = $(this).find(':selected').map(function(){
      return this.value;
    }).get().join(' or ~');
    myLocations += "~";  myLocations += filters[2];
    filters[2] = myLocations;
    $('table').trigger('search', [filters]);
  });
```

See the [`$.tablesorter.getFilters()` reference](https://mottie.github.io/tablesorter/docs/#function-getfilters).

