I think the issue is that you need to call `screen.clear()` before you start printing anything.  For example, this works for me:

    def demo(screen):
      screen.clear()
      while True:
        date = time.strftime("%d/%m/%Y %H:%M:%S")
        screen.print_at('Test menu', 0, 0)
        screen.print_at(date, screen.width-len(date), 0)
        screen.print_at('1) Some test menu entry', 3, 2)
        screen.print_at('2) Another test menu entry', 3, 3)
        ev = screen.get_key()
        if ev in (ord('Q'), ord('q')):
            return
        screen.refresh()

    while True:
      try:
        Screen.wrapper(demo)
        sys.exit()
      except ResizeScreenError:
        pass

