Hey @justinkterry, 

I whipped up a quick example for this - 

```
import numpy as np
import ray

@ray.remote
class ParameterServer(object):
    def __init__(self, weight_shard: np.ndarray):
        self.params = weight_shard.copy()

    def update_and_get_weights(self, grads):
        """Applies new update and returns weights."""
        self.params += grads.copy()
        return self.get_weights()

    def get_weights(self):
        return self.params


@ray.remote
class Worker(object):
    def __init__(self, weight_shard: np.ndarray, config):
        self.params = weight_shard.copy()
        self.config = config

    def compute_grad(self):
        return np.ones_like(self.params)

    def loop(self, ps):
        # runs update loop asynchronously
        for i in range(self.config["iterations"]):
            grads = self.compute_grad()
            self.params = ray.get(ps.update_and_get_weights.remote(grads))


if __name__ == '__main__':
    ray.init()
    num_workers = 4

    weight = np.random.rand(12)
    ps = ParameterServer.remote(weight)

    workers = [Worker.remote(weight, {"iterations": 100}) for i in range(4)]
    ray.get([w.loop.remote(ps) for w in workers])
    print(ray.get(ps.get_weights.remote()))
```

Let me know if this is a bit more useful. If so, I can update the documentation to include this example (with documentation and notes).

